Class DataList Extends %RegisteredObject
{
    Property Items As list Of %String;

    /// Get element at index (1-based)
    Method GetElement(index As %Integer) As %String
    {
        // BUGGY: No bounds checking - causes <SUBSCRIPT> error
        Quit ..Items.GetAt(index)
    }

    Method AddItem(value As %String)
    {
        Do ..Items.Insert(value)
    }
}

