Class TestDataList Extends %RegisteredObject
{
    ClassMethod TestGetElement()
    {
        Set list = ##class(DataList).%New()
        Do list.AddItem("first")
        Do list.AddItem("second")

        // Test valid index
        Set result = list.GetElement(1)
        If (result '= "first") {
            Throw ##class(%Exception.General).%New("GetElement(1) failed: got "_result)
        }

        // Test out of bounds - should return empty string, not error
        Set result = list.GetElement(99)
        If (result '= "") {
            Throw ##class(%Exception.General).%New("GetElement(99) should return empty: got "_result)
        }

        // Test zero index
        Set result = list.GetElement(0)
        If (result '= "") {
            Throw ##class(%Exception.General).%New("GetElement(0) should return empty: got "_result)
        }
    }
}
